1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
17	
18	const basePremium = (item: any): number =>
19	  BASE_PREMIUMS[item.type] ?? 0;
20	
21	const groupByType = (items: any[]): Record<string, number> =>
22	  items.reduce(
23	    (counts: Record<string, number>, item: any) => ({
24	      ...counts,
25	      [item.type]: (counts[item.type] ?? 0) + 1,
26	    }),
27	    {},
28	  );
29	
30	const componentGroupPremium = (type: string, count: number): number =>
31	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
32	
33	const itemSurcharges = (item: any, base: number): number => {
34	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
35	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
36	  return curseSurcharge + enchantmentSurcharge;
37	};
38	
39	const quotePremium = (items: any[], customer: any, quoteIndex: number): number => {
40	  const components = items.filter(isComponent);
41	  const nonComponents = items.filter((item: any) => !isComponent(item));
42	  const componentTotal = Object.entries(groupByType(components)).reduce(
43	    (sum: number, [type, count]: [string, number]) => sum + componentGroupPremium(type, count),
44	    0,
45	  );
46	  const { base: nonComponentBase, surcharges: surchargesTotal } = nonComponents.reduce(
47	    (acc, item: any) => {
48	      const b = basePremium(item);
49	      return { base: acc.base + b, surcharges: acc.surcharges + itemSurcharges(item, b) };
50	    },
51	    { base: 0, surcharges: 0 },
52	  );
53	  const policyBasePremium = nonComponentBase + componentTotal;
54	  const firstInsurance = policyBasePremium * 0.1;
55	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? -policyBasePremium * 0.2 : 0;
56	  const followUpDiscount = quoteIndex > 0 ? -policyBasePremium * 0.15 : 0;
57	  return Math.ceil(policyBasePremium + surchargesTotal + firstInsurance + loyaltyDiscount + followUpDiscount + PROCESSING_FEE);
58	};
59	
60	export const processScenario = (scenario: any): any => {
61	  let quoteIndex = 0;
62	  return {
63	    results: scenario.steps.map((step: any) => {
64	      const result = { premium: quotePremium(step.items, scenario.customer, quoteIndex) };
65	      quoteIndex++;
66	      return result;
67	    }),
68	  };
69	};
